import React from 'react';
import { motion } from 'framer-motion';
import { User, Mail, Briefcase, Star, Settings, Shield, Zap, Send, LayoutDashboard, Rocket } from 'lucide-react';
import Navbar from '../components/Navbar';

const Profile = () => {
  const user = {
    name: "Alex Johnson",
    email: "alex.j@campus.edu",
    role: "Senior Provider / Physics Tutor",
    bio: "Physics enthusiast and full-stack developer. Helping students ace their labs and code their dreams since 2022.",
    skills: ["Quantum Physics", "React", "Node.js", "Data Visualization", "Calculus"],
    reputation: 4.9,
    completions: 124,
    safetyScore: 98,
  };

  return (
    <div className="min-h-screen pt-24 pb-40 px-6 md:px-12 bg-background-dark/95">
      <Navbar />

      <div className="max-w-5xl mx-auto">
        {/* Profile Header */}
        <motion.div 
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          className="glass-card p-10 md:p-16 mb-12 relative overflow-hidden"
        >
          <div className="absolute top-0 right-0 w-64 h-64 bg-primary-600/10 blur-[120px] -z-10 bg-blue-600/20"></div>

          <div className="flex flex-col md:flex-row items-center md:items-start space-y-8 md:space-y-0 md:space-x-12">
            <div className="w-32 h-32 md:w-48 md:h-48 bg-gradient-to-br from-primary-400 to-primary-700 rounded-3xl flex items-center justify-center shadow-2xl transform rotate-6 hover:rotate-0 transition-all duration-300">
              <span className="text-white text-5xl md:text-7xl font-black uppercase">{user.name[0]}</span>
              <div className="absolute -bottom-4 -right-4 w-12 h-12 bg-green-500 border-8 border-background-dark rounded-full group-hover:scale-110 transition-transform"></div>
            </div>

            <div className="flex-1 text-center md:text-left">
              <div className="flex flex-col md:flex-row md:items-center md:justify-between mb-6">
                <div>
                  <h1 className="text-4xl md:text-5xl font-black mb-2 uppercase tracking-tighter">{user.name}</h1>
                  <p className="text-gray-400 font-bold uppercase tracking-widest text-sm flex items-center justify-center md:justify-start">
                    <Briefcase size={16} className="mr-2 text-primary-400" />
                    {user.role}
                  </p>
                </div>
                <button className="btn-secondary mt-6 md:mt-0 font-black uppercase text-xs tracking-widest flex items-center justify-center">
                  <Settings size={16} className="mr-2" /> Edit Profile
                </button>
              </div>

              <p className="text-lg text-gray-500 max-w-2xl leading-relaxed italic animate-fade-in mb-8">
                "{user.bio}"
              </p>

              <div className="flex flex-wrap gap-3 justify-center md:justify-start">
                {user.skills.map(skill => (
                  <span key={skill} className="px-4 py-2 bg-white/5 border border-white/10 rounded-xl text-sm font-bold uppercase tracking-tight text-gray-400 hover:bg-white/10 hover:text-white transition-all shadow-xl">
                    {skill}
                  </span>
                ))}
              </div>
            </div>
          </div>
        </motion.div>

        {/* Stats Section */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            <StatCard icon={Star} label="Reputation" value={user.reputation} color="text-yellow-400" />
            <StatCard icon={Zap} label="Tasks Done" value={user.completions} color="text-purple-400" />
            <StatCard icon={Shield} label="Safety Score" value={user.safetyScore + '%'} color="text-green-400" />
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ icon: Icon, label, value, color }) => (
  <motion.div 
    whileHover={{ y: -10 }}
    className="glass p-10 rounded-3xl text-center group transition-all duration-300 shadow-2xl overflow-hidden relative"
  >
    <div className="absolute -top-10 -left-10 w-32 h-32 bg-primary-600/5 blur-3xl -z-10 bg-blue-600/10"></div>
    <div className="w-16 h-16 bg-white/5 rounded-2xl flex items-center justify-center mx-auto mb-6 group-hover:bg-primary-600 group-hover:text-white transition-all">
      <Icon className={color + " group-hover:text-white transition-all"} size={32} />
    </div>
    <h3 className="text-4xl font-black mb-2 uppercase tracking-tighter">{value}</h3>
    <p className="text-gray-500 font-extrabold uppercase text-sm tracking-widest opacity-60 italic">{label}</p>
  </motion.div>
);

export default Profile;
